((java.util.function.IntSupplier) () -> {
    // 1) 기존 슬롯 탐색
    int target = -1;
    for (int i = 0; i < 4; i++) {
        if (slotBranches[i] == agent.branchId) { target = i; break; }
    }

    // 2) 없으면 빈 슬롯 할당 + batchSize 초기 설정
    if (target == -1) {
        for (int i = 0; i < 4; i++) {
            if (slotBranches[i] == 0) {
                slotBranches[i] = agent.branchId;
                target = i;
                int rem = branchRemainingTotal.getOrDefault(agent.branchId, 0);
                batchSizes[target] = min(32, rem);
                break;
            }
        }
    }

    // 3) 빈 슬롯도 없으면 잔여량 가장 적은 슬롯 강제 할당
    if (target == -1) {
        int minRem = Integer.MAX_VALUE;
        for (int i = 0; i < 4; i++) {
            int rem = branchRemainingTotal.getOrDefault(slotBranches[i], 0);
            if (rem < minRem) { minRem = rem; target = i; }
        }
    }

    agent.slotIndex = target;
    return target + 1;
}).getAsInt()

