int branchId0 = slotBranches[0];
int rem0 = branchRemainingTotal.getOrDefault(branchId0, 0) - 32;
branchRemainingTotal.put(branchId0, rem0);
if (rem0 <= 0) {
    completedBranches++;
    slotBranches[0] = 0;
} else {
    batchSizes[0] = min(32, rem0);
}
